import{_ as a,o as s,c as e,a2 as n}from"./chunks/framework.CQMe4Urg.js";const u=JSON.parse('{"title":"前沿方向 · 入门篇","description":"","frontmatter":{},"headers":[],"relativePath":"16-frontier/beginner.md","filePath":"16-frontier/beginner.md","lastUpdated":1776333512000}'),i={name:"16-frontier/beginner.md"};function l(o,t,p,r,d,h){return s(),e("div",null,[...t[0]||(t[0]=[n(`<h1 id="前沿方向-·-入门篇" tabindex="-1">前沿方向 · 入门篇 <a class="header-anchor" href="#前沿方向-·-入门篇" aria-label="Permalink to &quot;前沿方向 · 入门篇&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">学习目标</p><ul><li>理解 Computer Use（让 AI 操作电脑）的概念和意义</li><li>理解 Code Agent（让 AI 写代码）的概念和工作方式</li><li>了解这些前沿方向为什么重要，以及它们目前的局限性</li></ul></div><div class="info custom-block"><p class="custom-block-title">学完你能做到</p><ul><li>向同事清楚解释 Computer Use 和 Code Agent 是什么</li><li>判断你的业务场景适不适合用这些技术</li><li>对 Agent 技术的未来趋势有基本的认知</li></ul></div><h2 id="computer-use-让-ai-操作你的电脑" tabindex="-1">Computer Use：让 AI 操作你的电脑 <a class="header-anchor" href="#computer-use-让-ai-操作你的电脑" aria-label="Permalink to &quot;Computer Use：让 AI 操作你的电脑&quot;">​</a></h2><h3 id="从-api-调用到界面操作" tabindex="-1">从 API 调用到界面操作 <a class="header-anchor" href="#从-api-调用到界面操作" aria-label="Permalink to &quot;从 API 调用到界面操作&quot;">​</a></h3><p>前面章节讲的工具调用（Tool Use），本质上是让 AI 调用写好的函数——搜索 API、数据库查询、发消息。这些都是&quot;程序员路线&quot;，需要提前写好接口。</p><p>Computer Use 走的是另一条路——&quot;普通用户路线&quot;：AI 直接看到你的屏幕画面，然后像人一样点击鼠标、敲键盘。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>传统 Tool Use:                Computer Use:</span></span>
<span class="line"><span>用户 → AI → search()          用户 → AI → [看屏幕] → [点鼠标] → [打字]</span></span>
<span class="line"><span>      ← 结果 ←                       ← 看到结果 ←</span></span></code></pre></div><p>打个比方：Tool Use 是给 AI 一把特定的钥匙开特定的门，Computer Use 是教 AI 自己去找门、找钥匙、开门。</p><h3 id="它是怎么工作的" tabindex="-1">它是怎么工作的 <a class="header-anchor" href="#它是怎么工作的" aria-label="Permalink to &quot;它是怎么工作的&quot;">​</a></h3><p>Computer Use 的核心是一个不断重复的循环：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>截取屏幕截图</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>把截图发给 AI 模型</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>AI 分析截图，决定下一步操作（点击某个按钮、输入文字、滚动页面...）</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>执行操作</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>回到第一步，截取新的屏幕截图</span></span></code></pre></div><p>就像一个远程桌面操作员——看屏幕、想一想、操作、再看屏幕...</p><h3 id="什么时候该用" tabindex="-1">什么时候该用 <a class="header-anchor" href="#什么时候该用" aria-label="Permalink to &quot;什么时候该用&quot;">​</a></h3><table tabindex="0"><thead><tr><th>场景</th><th>适合程度</th><th>原因</th></tr></thead><tbody><tr><td>操作没有 API 的老系统</td><td>非常适合</td><td>只有 GUI，没有其他选择</td></tr><tr><td>跨多个 GUI 应用的操作</td><td>适合</td><td>一个流程涉及多个软件</td></tr><tr><td>快速验证想法</td><td>适合</td><td>先跑通再决定是否做 API 对接</td></tr><tr><td>有现成 API 的场景</td><td>不适合</td><td>API 更快、更准、更便宜</td></tr><tr><td>高频重复任务</td><td>不适合</td><td>写脚本或用 Selenium 更可靠</td></tr><tr><td>实时交互场景</td><td>不适合</td><td>每一步都要截图 + AI 推理，太慢</td></tr></tbody></table><h3 id="当前的局限" tabindex="-1">当前的局限 <a class="header-anchor" href="#当前的局限" aria-label="Permalink to &quot;当前的局限&quot;">​</a></h3><p>Computer Use 目前还有明显的限制，了解这些才不会踩坑：</p><ul><li><strong>速度慢</strong>：每一步都要截图（约 1 秒）+ AI 推理（约 2-5 秒），简单操作都要几秒钟</li><li><strong>坐标不精确</strong>：AI 对屏幕元素的定位有误差，小按钮容易点错</li><li><strong>成本高</strong>：每张截图约消耗 1000-2000 tokens，一个任务可能需要 10-30 张截图</li><li><strong>安全风险</strong>：AI 直接控制电脑，误操作不可逆（误删文件、误发邮件）</li></ul><div class="warning custom-block"><p class="custom-block-title">务必在沙箱中运行</p><p>Computer Use 让 AI 获得了和你一样的电脑操作权限。Anthropic 官方提供了 Docker 镜像作为安全沙箱：</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">services</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  computer-use</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    image</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">ghcr.io/anthropics/anthropic-quickstarts:computer-use-demo-latest</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    ports</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;8501:8501&quot;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # Streamlit UI</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;6080:6080&quot;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 浏览器访问虚拟桌面</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    environment</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">ANTHROPIC_API_KEY=\${ANTHROPIC_API_KEY}</span></span></code></pre></div></div><h2 id="code-agent-让-ai-成为编程搭档" tabindex="-1">Code Agent：让 AI 成为编程搭档 <a class="header-anchor" href="#code-agent-让-ai-成为编程搭档" aria-label="Permalink to &quot;Code Agent：让 AI 成为编程搭档&quot;">​</a></h2><h3 id="从-写代码-到-做开发" tabindex="-1">从&quot;写代码&quot;到&quot;做开发&quot; <a class="header-anchor" href="#从-写代码-到-做开发" aria-label="Permalink to &quot;从&quot;写代码&quot;到&quot;做开发&quot;&quot;">​</a></h3><p>ChatGPT 和 Claude 早就能写代码了。但&quot;写代码&quot;和&quot;做开发&quot;是两回事。</p><p><strong>写代码</strong>：你告诉 AI &quot;写一个排序函数&quot;，它给你一段代码。</p><p><strong>做开发（Code Agent）</strong>：你说&quot;修复登录页面的验证 bug&quot;，AI 自己去搜索相关文件、阅读代码、理解逻辑、修改代码、运行测试、确认修复——完整的开发流程。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户需求: &quot;修复登录页面的验证 bug&quot;</span></span>
<span class="line"><span>    |</span></span>
<span class="line"><span>    v</span></span>
<span class="line"><span>理解阶段: 搜索相关代码文件 → 阅读代码 → 理解结构</span></span>
<span class="line"><span>    |</span></span>
<span class="line"><span>    v</span></span>
<span class="line"><span>规划阶段: 分析 bug 原因 → 制定修复方案</span></span>
<span class="line"><span>    |</span></span>
<span class="line"><span>    v</span></span>
<span class="line"><span>修改阶段: 编辑代码 → 可能创建新文件</span></span>
<span class="line"><span>    |</span></span>
<span class="line"><span>    v</span></span>
<span class="line"><span>验证阶段: 运行测试 → 检查结果 → 如有问题返回修改</span></span></code></pre></div><h3 id="code-agent-的四类核心工具" tabindex="-1">Code Agent 的四类核心工具 <a class="header-anchor" href="#code-agent-的四类核心工具" aria-label="Permalink to &quot;Code Agent 的四类核心工具&quot;">​</a></h3><p>Code Agent 不需要几十个工具，四类就够了：</p><table tabindex="0"><thead><tr><th>工具</th><th>作用</th><th>举例</th></tr></thead><tbody><tr><td><strong>搜索</strong></td><td>在代码库中找到相关文件和代码</td><td><code>grep_search(&quot;login&quot;, path=&quot;src/&quot;)</code></td></tr><tr><td><strong>读取</strong></td><td>查看文件内容</td><td><code>read_file(&quot;src/auth.py&quot;)</code></td></tr><tr><td><strong>编辑</strong></td><td>修改代码（精确替换，不是重写）</td><td><code>edit_file(&quot;src/auth.py&quot;, old=&quot;...&quot;, new=&quot;...&quot;)</code></td></tr><tr><td><strong>执行</strong></td><td>运行命令（测试、lint 等）</td><td><code>run_command(&quot;pytest tests/&quot;)</code></td></tr></tbody></table><p>注意&quot;编辑&quot;这个工具的设计——<strong>精确替换而不是重写整个文件</strong>。这是 Claude Code 等成熟工具的核心设计思想：改动越小，引入新 bug 的概率越低。</p><h3 id="claude-code-的设计理念" tabindex="-1">Claude Code 的设计理念 <a class="header-anchor" href="#claude-code-的设计理念" aria-label="Permalink to &quot;Claude Code 的设计理念&quot;">​</a></h3><p>Claude Code 是 Anthropic 的 CLI 编程工具，它的设计值得学习：</p><ol><li><strong>工具精而不多</strong>：搜索、读取、编辑、终端命令四类搞定一切</li><li><strong>编辑而非重写</strong>：用字符串替换（old_string -&gt; new_string）修改代码</li><li><strong>渐进式理解</strong>：先搜索 → 再阅读 → 最后才修改，像人类开发者一样</li><li><strong>项目约定</strong>：通过 CLAUDE.md 让 Agent 理解项目的编码规范和约定</li></ol><h3 id="什么时候用-code-agent" tabindex="-1">什么时候用 Code Agent <a class="header-anchor" href="#什么时候用-code-agent" aria-label="Permalink to &quot;什么时候用 Code Agent&quot;">​</a></h3><table tabindex="0"><thead><tr><th>任务</th><th>适合程度</th><th>说明</th></tr></thead><tbody><tr><td>Bug 修复</td><td>非常适合</td><td>搜索定位 + 精确修改 + 测试验证</td></tr><tr><td>代码重构</td><td>适合</td><td>理解代码结构后批量修改</td></tr><tr><td>写新功能</td><td>适合</td><td>参考已有代码风格来写</td></tr><tr><td>架构设计</td><td>较弱</td><td>还是需要人类把控方向</td></tr></tbody></table><h2 id="为什么这些方向重要" tabindex="-1">为什么这些方向重要 <a class="header-anchor" href="#为什么这些方向重要" aria-label="Permalink to &quot;为什么这些方向重要&quot;">​</a></h2><h3 id="agent-的能力边界在扩大" tabindex="-1">Agent 的能力边界在扩大 <a class="header-anchor" href="#agent-的能力边界在扩大" aria-label="Permalink to &quot;Agent 的能力边界在扩大&quot;">​</a></h3><p>回顾 Agent 的进化路径：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>2023: 文本对话 → 调用 API（Tool Use）</span></span>
<span class="line"><span>2024: 操作电脑（Computer Use）→ 自主编程（Code Agent）</span></span>
<span class="line"><span>2025: 自主学习 → Agent 协作</span></span>
<span class="line"><span>未来: ???</span></span></code></pre></div><p>每一步进化都让 Agent 能做的事情翻了一倍。Tool Use 让 Agent 能调用几十种 API，Computer Use 让 Agent 能操作任何有界面的软件，Code Agent 让 Agent 能修改自己运行的代码。</p><h3 id="三个方向的共同趋势" tabindex="-1">三个方向的共同趋势 <a class="header-anchor" href="#三个方向的共同趋势" aria-label="Permalink to &quot;三个方向的共同趋势&quot;">​</a></h3><p>这些前沿方向有一个共同的趋势：<strong>Agent 正在从&quot;工具调用者&quot;进化为&quot;自主行动者&quot;</strong>。</p><ul><li>Tool Use：你告诉 Agent 用哪个工具</li><li>Computer Use：Agent 自己决定怎么操作界面</li><li>Code Agent：Agent 自己搜索、理解、修改代码</li><li>自主学习（高级篇会讲）：Agent 自己创造新工具</li></ul><p>这个趋势意味着什么？对开发者来说，你不再需要为 Agent 预先定义所有能力，Agent 可以自己去&quot;发现&quot;和&quot;学习&quot;新的能力。</p><h2 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to &quot;小结&quot;">​</a></h2><p>三个最值得关注的前沿方向：</p><ol><li><strong>Computer Use</strong>：AI 操控 GUI 界面，适合没有 API 的遗留系统和跨应用操作，但目前速度慢、成本高</li><li><strong>Code Agent</strong>：AI 自主完成完整开发流程（搜索 -&gt; 理解 -&gt; 修改 -&gt; 验证），已经进入生产可用阶段</li><li><strong>共同趋势</strong>：Agent 的能力边界在持续扩大，从调用预定义工具到自主行动</li></ol><h2 id="练习" tabindex="-1">练习 <a class="header-anchor" href="#练习" aria-label="Permalink to &quot;练习&quot;">​</a></h2><ol><li>思考你的工作中有哪些&quot;没有 API 只有 GUI&quot;的系统，列出 3 个可能用 Computer Use 的场景</li><li>如果让你设计一个 Code Agent，除了搜索、读取、编辑、执行四类工具，你还会加什么工具？为什么？</li><li>尝试用 Anthropic 的 Computer Use Docker Demo 完成一个简单任务（如打开浏览器搜索）</li></ol><h2 id="参考资源" tabindex="-1">参考资源 <a class="header-anchor" href="#参考资源" aria-label="Permalink to &quot;参考资源&quot;">​</a></h2><ul><li><a href="https://docs.anthropic.com/en/docs/build-with-claude/computer-use" target="_blank" rel="noreferrer">Anthropic Computer Use 文档</a> -- 官方 Computer Use API 文档</li><li><a href="https://docs.anthropic.com/en/docs/claude-code" target="_blank" rel="noreferrer">Claude Code 官方文档</a> -- Anthropic CLI 编程工具</li><li><a href="https://www.anthropic.com/news/3-5-sonnet-computer-use" target="_blank" rel="noreferrer">Computer Use 发布公告</a> -- Anthropic 博客介绍</li><li><a href="https://www.swebench.com/" target="_blank" rel="noreferrer">SWE-bench</a> -- Code Agent 基准测试（看看 AI 修 bug 的能力到哪了）</li><li><a href="https://os-world.github.io/" target="_blank" rel="noreferrer">OSWorld Benchmark</a> -- Computer Use 能力评测基准</li></ul>`,50)])])}const g=a(i,[["render",l]]);export{u as __pageData,g as default};
